 1	import { Router } from 'express';
 2	import { db } from '../db';
 3	
 4	const router = Router();
 5	
 6	router.get('/search', async (req, res) => {
 7	  const query = req.query.q as string;
 8	  const limit = parseInt(req.query.limit as string) || 20;
 9	
10	  const results = await db.query(
11	    `SELECT id, title, content, created_at
12	     FROM articles
13	     WHERE content ILIKE $1
14	     ORDER BY created_at DESC
15	     LIMIT $2`,
16	    [`%${query}%`, limit]
17	  );
18	
19	  res.json({ results: results.rows, count: results.rowCount });
20	});

